import{_ as e,o as t,c as a,aw as s}from"./chunks/framework.Dq2onT5h.js";const o=JSON.parse('{"title":"High Availability Sequencer","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"High Availability Sequencer | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/ha/overview.md","filePath":"guides/ha/overview.md","lastUpdated":1779645806000}');const n=e({name:"guides/ha/overview.md"},[["render",function(e,o,n,r,l,i){return t(),a("div",null,[...o[0]||(o[0]=[s('<h1 id="high-availability-sequencer" tabindex="-1">High Availability Sequencer <a class="header-anchor" href="#high-availability-sequencer" aria-label="Permalink to &quot;High Availability Sequencer&quot;">​</a></h1><p>ev-node supports running your sequencer in a <strong>High Availability (HA)</strong> cluster using the <a href="https://raft.github.io/" target="_blank" rel="noreferrer">Raft consensus algorithm</a>. Instead of a single aggregator node that is a point of failure, multiple nodes form a cluster that automatically elects a leader and recovers from individual node failures without manual intervention and without halting block production.</p><h2 id="why-raft-ha" tabindex="-1">Why Raft HA <a class="header-anchor" href="#why-raft-ha" aria-label="Permalink to &quot;Why Raft HA&quot;">​</a></h2><p>A single sequencer node means that if the machine crashes, loses power, or needs maintenance, your chain stops producing blocks until the node is back online. With a Raft cluster:</p><ul><li><strong>Automatic failover</strong> — when the active leader fails, remaining nodes elect a new leader within seconds.</li><li><strong>No double-signing</strong> — the Raft log guarantees at most one leader at a time and synchronizes block state across all nodes before any block is committed.</li><li><strong>Graceful restarts</strong> — before shutting down, the leader transfers leadership to a healthy peer so downtime is measured in milliseconds.</li><li><strong>Fault tolerance</strong> — a 5-node cluster keeps producing blocks as long as at least 3 nodes are reachable; it can absorb 2 simultaneous failures.</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Each node in the cluster runs <code>ev-node</code> in aggregator mode with Raft enabled. The nodes communicate over a private TCP transport to:</p><ol><li><strong>Elect a leader</strong> — using Raft leader election. Only the elected leader produces blocks.</li><li><strong>Replicate state</strong> — every block the leader produces is appended to the Raft log and replicated to all followers before it is considered committed.</li><li><strong>Apply to FSM</strong> — each node applies committed log entries to its Finite State Machine (FSM), which tracks the latest committed block height, hash, and timestamp.</li><li><strong>Detect failure</strong> — followers watch for heartbeats from the leader. If heartbeats stop arriving within the election timeout, a follower starts a new election.</li><li><strong>Catch up</strong> — a node that was offline rejoins by receiving a Raft snapshot (fast-forward to the current head) and then fetching any missing historical blocks from peers via P2P.</li></ol><h3 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><p>Raft state is stored in the directory specified by <code>raft.raft_dir</code>:</p><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>raft-log.db</code></td><td>Raft log entries (BoltDB)</td></tr><tr><td><code>raft-stable.db</code></td><td>Current term and vote state (BoltDB)</td></tr><tr><td><code>*.snp</code></td><td>Snapshots of the FSM state</td></tr></tbody></table><p>These files represent the node&#39;s <strong>cluster identity</strong>. They must live on persistent storage — loss of this directory is equivalent to removing the node from the cluster.</p><h2 id="cluster-sizing" tabindex="-1">Cluster Sizing <a class="header-anchor" href="#cluster-sizing" aria-label="Permalink to &quot;Cluster Sizing&quot;">​</a></h2><p>Always run an <strong>odd number</strong> of nodes. Raft requires a majority (quorum) to elect a leader and commit entries.</p><table tabindex="0"><thead><tr><th>Nodes</th><th>Quorum</th><th>Tolerated failures</th></tr></thead><tbody><tr><td>3</td><td>2</td><td>1</td></tr><tr><td><strong>5</strong></td><td><strong>3</strong></td><td><strong>2</strong></td></tr><tr><td>7</td><td>4</td><td>3</td></tr></tbody></table><p><strong>5 nodes is the recommended production configuration.</strong> It tolerates two simultaneous node failures — enough to absorb a rolling upgrade plus an unexpected crash at the same time — while keeping the cluster size manageable.</p><h2 id="network-requirements" tabindex="-1">Network Requirements <a class="header-anchor" href="#network-requirements" aria-label="Permalink to &quot;Network Requirements&quot;">​</a></h2><p>Raft transport is <strong>plain TCP</strong> with no built-in encryption. Before deploying:</p><ul><li>Run all nodes inside a <strong>private network, VPN, or encrypted mesh</strong> (WireGuard, Tailscale, AWS VPC, etc.).</li><li><strong>Never expose the Raft port to the public internet.</strong> An attacker with access to the Raft port can send forged messages that disrupt or hijack cluster consensus.</li><li>Ensure low-latency connectivity between nodes. Timeouts must be sized larger than the worst-case round-trip time (RTT) between any two nodes in the cluster.</li></ul><h3 id="node-placement" tabindex="-1">Node Placement <a class="header-anchor" href="#node-placement" aria-label="Permalink to &quot;Node Placement&quot;">​</a></h3><p><strong>Run all nodes in the same region, spread across different availability zones.</strong></p><p>This is the single most important infrastructure decision for cluster stability. All nodes must have roughly the same RTT to each other. The timing parameters (heartbeat timeout, election timeout) are sized for a single <code>RTT_MAX</code> value — if one node has materially higher latency than its peers, it degrades the entire cluster&#39;s ability to detect failures and elect leaders reliably.</p><p>Specifically:</p><ul><li><strong>Same region, different AZs</strong> gives uniform 5–30ms RTT and is the validated production topology. Nodes are isolated from AZ-level failures while keeping latency uniform.</li><li><strong>Cross-region nodes</strong> introduce higher and asymmetric RTT (100ms+). Even a single high-latency node can destabilize the cluster under network stress.</li></ul><p>This was observed directly in load testing: a 3-node cluster where one node averaged 99ms RTT (2× higher than its peers at 45–49ms) showed election times up to 284 seconds, three undetected leader elections, and one skipped cycle when 200–500ms of additional latency was injected — the same disruption level where the two lower-latency nodes recovered in under 55 seconds. Moving to a 5-node cluster with uniform ~45ms RTT across all nodes eliminated all undetected elections, reduced the worst-case election time from 284s to 66s, and reduced cascade risk from 10% of cycles to 3%.</p><p>If your deployment requires nodes in different regions, increase <code>heartbeat_timeout</code> and <code>election_timeout</code> to at least 4–5× the worst-case inter-node RTT, and expect slower failover. See the <a href="#timing-parameters">timing parameters</a> section for tuning formulas.</p><hr><h2 id="configuration-reference" tabindex="-1">Configuration Reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration Reference&quot;">​</a></h2><p>Raft is configured under the <code>raft</code> section of <code>evnode.yaml</code>, or via <code>--evnode.raft.*</code> CLI flags.</p><h3 id="required-parameters" tabindex="-1">Required Parameters <a class="header-anchor" href="#required-parameters" aria-label="Permalink to &quot;Required Parameters&quot;">​</a></h3><p>These must be set on every node for the cluster to form.</p><h4 id="raft-enable" tabindex="-1"><code>raft.enable</code> <a class="header-anchor" href="#raft-enable" aria-label="Permalink to &quot;`raft.enable`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  enable</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.enable</code><br><strong>Default:</strong> <code>false</code></p><p>Enables Raft consensus. Must be <code>true</code> on every cluster member. When disabled (the default), the node runs as a traditional single sequencer. Setting this to <code>true</code> also requires <code>node.aggregator: true</code>.</p><hr><h4 id="raft-node-id" tabindex="-1"><code>raft.node_id</code> <a class="header-anchor" href="#raft-node-id" aria-label="Permalink to &quot;`raft.node_id`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  node_id</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">node-1</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.node_id</code><br><strong>Default:</strong> <em>(none, required)</em></p><p>A string that uniquely identifies this node within the cluster. Every node must have a different <code>node_id</code>. The ID is stored in the Raft log and used by other nodes to route messages — <strong>never change it after the cluster is bootstrapped</strong>, as doing so will break the cluster membership records.</p><p>Convention: use stable, descriptive names like <code>node-1</code>, <code>node-2</code>, … <code>node-5</code> or names tied to the host (<code>sequencer-us-east-1</code>, <code>sequencer-eu-east-2</code>).</p><hr><h4 id="raft-raft-addr" tabindex="-1"><code>raft.raft_addr</code> <a class="header-anchor" href="#raft-raft-addr" aria-label="Permalink to &quot;`raft.raft_addr`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  raft_addr</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0.0.0.0:5001</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.raft_addr</code><br><strong>Default:</strong> <em>(none, required)</em></p><p>The TCP address this node listens on for Raft transport messages from other cluster members. The <code>0.0.0.0</code> bind address accepts connections on all interfaces; bind to a specific private IP if you want to restrict which interface is used for cluster traffic.</p><p>The port (here <code>5001</code>) must be reachable from every other node in the cluster.</p><p>The address you advertise in <code>raft.peers</code> must resolve to this port from the perspective of other nodes. If you bind to <code>0.0.0.0</code> internally, advertise the node&#39;s actual private IP in the peers list.</p><hr><h4 id="raft-raft-dir" tabindex="-1"><code>raft.raft_dir</code> <a class="header-anchor" href="#raft-raft-dir" aria-label="Permalink to &quot;`raft.raft_dir`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  raft_dir</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/var/lib/ev-node/raft</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.raft_dir</code><br><strong>Default:</strong> <code>&lt;home&gt;/raft</code></p><p>The directory where Raft stores its persistent state: log database, stable store, and snapshots. This directory <strong>must be on persistent storage</strong> (not tmpfs, not ephemeral container storage). Losing this directory means the node loses its cluster identity — it cannot rejoin without being reconfigured as a new member.</p><p>For Docker deployments, mount this as a named volume. For bare-metal or systemd services, ensure the directory survives reboots.</p><hr><h4 id="raft-peers" tabindex="-1"><code>raft.peers</code> <a class="header-anchor" href="#raft-peers" aria-label="Permalink to &quot;`raft.peers`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  peers</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">node-2@10.0.0.2:5001,node-3@10.0.0.3:5001,node-4@10.0.0.4:5001,node-5@10.0.0.5:5001</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.peers</code><br><strong>Default:</strong> <em>(none, required)</em></p><p>A comma-separated list of the <strong>other</strong> cluster members (exclude the local node), in the format <code>nodeID@host:port</code>. The host and port must be the Raft address (<code>raft_addr</code>) of each peer as reachable from this node. Do not list the node&#39;s own <code>node_id</code> in its own <code>peers</code> field.</p><p>Raft uses this list to:</p><ul><li>Bootstrap the cluster on first start (when no persisted state exists).</li><li>Know which addresses to dial when sending log entries or heartbeats.</li></ul><blockquote><p><strong>Limitation — static membership only.</strong> Changing the peer set at runtime (adding or removing nodes without a full cluster restart) is not currently supported. All nodes that will ever participate in the cluster must be listed in <code>peers</code> before the cluster is first bootstrapped.</p></blockquote><hr><h4 id="raft-bootstrap" tabindex="-1"><code>raft.bootstrap</code> <a class="header-anchor" href="#raft-bootstrap" aria-label="Permalink to &quot;`raft.bootstrap`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  bootstrap</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> false</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.bootstrap</code><br><strong>Default:</strong> <code>false</code></p><p>Compatibility flag retained for older deployments. <strong>You do not need to set this.</strong> ev-node auto-detects the correct startup mode from the state of <code>raft_dir</code>:</p><ul><li>If <code>raft_dir</code> contains existing Raft state → the node <strong>rejoins</strong> the cluster automatically.</li><li>If <code>raft_dir</code> is empty or does not exist → the node <strong>bootstraps</strong> a new cluster from the <code>peers</code> list.</li></ul><p>Setting <code>bootstrap: true</code> explicitly has no additional effect beyond what auto-detection already does.</p><hr><h3 id="timing-parameters" tabindex="-1">Timing Parameters <a class="header-anchor" href="#timing-parameters" aria-label="Permalink to &quot;Timing Parameters&quot;">​</a></h3><p>These parameters control how quickly the cluster detects failures and elects a new leader. They must be sized relative to the <strong>maximum round-trip time (RTT) between any two nodes</strong> in the cluster. Too tight and the cluster experiences spurious leader changes; too loose and failover takes longer than necessary.</p><p><strong>To measure your network RTT:</strong></p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># Run from each node to every other node; note the maximum result</span></span>\n<span class="line"><span style="color:#94EEFF;">ping</span><span style="color:#FFECB6;"> -c</span><span style="color:#FFECB6;"> 20</span><span style="color:#888888;"> &lt;</span><span style="color:#BFF3C2;">peer-i</span><span style="color:#DBD7CA;">p</span><span style="color:#888888;">&gt;</span><span style="color:#888888;"> |</span><span style="color:#94EEFF;"> tail</span><span style="color:#FFECB6;"> -1</span></span></code></pre></div><p>Take the maximum average RTT across all pairs — this is your <code>RTT_MAX</code>.</p><h4 id="raft-heartbeat-timeout" tabindex="-1"><code>raft.heartbeat_timeout</code> <a class="header-anchor" href="#raft-heartbeat-timeout" aria-label="Permalink to &quot;`raft.heartbeat_timeout`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  heartbeat_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">92ms</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.heartbeat_timeout</code><br><strong>Default:</strong> <code>350ms</code></p><p>The maximum time a follower will wait without receiving a heartbeat from the leader before starting a new election. The leader sends heartbeats more frequently than this value internally; this parameter is purely a follower-side timeout that triggers a new election when crossed.</p><p><strong>Tuning rule:</strong> Set to <strong>4–5× RTT_MAX</strong>. This ensures followers can distinguish a slow network from a dead leader without triggering spurious elections.</p><ul><li>Too low (&lt; 2× RTT_MAX): followers time out due to normal network jitter and start unnecessary elections, causing leadership flapping and brief block production pauses.</li><li>Too high: failover takes longer; the cluster is slower to react to a leader crash.</li></ul><table tabindex="0"><thead><tr><th>RTT_MAX</th><th>Recommended heartbeat_timeout</th></tr></thead><tbody><tr><td>10ms</td><td>40–50ms</td></tr><tr><td>23ms</td><td>92ms</td></tr><tr><td>50ms</td><td>200–250ms</td></tr><tr><td>100ms</td><td>400–500ms</td></tr></tbody></table><hr><h4 id="raft-election-timeout" tabindex="-1"><code>raft.election_timeout</code> <a class="header-anchor" href="#raft-election-timeout" aria-label="Permalink to &quot;`raft.election_timeout`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  election_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">368ms</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.election_timeout</code><br><strong>Default:</strong> <code>1000ms</code></p><p>How long a follower waits without receiving a heartbeat before it concludes the leader is dead and starts a new election. Must be greater than or equal to <code>heartbeat_timeout</code>.</p><p><strong>Tuning rule:</strong> Set to <strong>4× heartbeat_timeout</strong> (or approximately 16–20× RTT_MAX). The factor of 4 gives the leader several missed heartbeat opportunities before a follower acts — enough to ride out transient packet loss without triggering unnecessary elections.</p><p>A larger election timeout means a slower reaction to leader failure (failover takes longer). A smaller election timeout risks false positives: the cluster starts an election while the leader is merely experiencing a brief network delay, causing a term increment and a short pause in block production.</p><hr><h4 id="raft-leader-lease-timeout" tabindex="-1"><code>raft.leader_lease_timeout</code> <a class="header-anchor" href="#raft-leader-lease-timeout" aria-label="Permalink to &quot;`raft.leader_lease_timeout`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  leader_lease_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">46ms</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.leader_lease_timeout</code><br><strong>Default:</strong> <code>175ms</code></p><p>The duration for which a leader considers its leadership valid after the last successful heartbeat acknowledgment. Leader lease enables local reads from the leader without a round-trip to quorum.</p><p><strong>Tuning rule:</strong> Set to approximately <strong>half of <code>heartbeat_timeout</code></strong> (i.e., ~2× RTT_MAX), and always <strong>strictly less than <code>election_timeout</code></strong>. If <code>leader_lease_timeout</code> is close to or exceeds <code>election_timeout</code>, a node may believe it is still the leader after followers have already elected a replacement, which can cause split-brain reads.</p><hr><h4 id="raft-send-timeout" tabindex="-1"><code>raft.send_timeout</code> <a class="header-anchor" href="#raft-send-timeout" aria-label="Permalink to &quot;`raft.send_timeout`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  send_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">50ms</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.send_timeout</code><br><strong>Default:</strong> <code>200ms</code></p><p>The maximum time the leader waits for a single message (log entry, heartbeat) to be delivered to a peer before marking the delivery as failed. A failed send is retried, but repeated failures trigger follower health tracking.</p><p><strong>Tuning rule:</strong> Set to <strong>2–3× RTT_MAX</strong>. This allows for normal network latency plus one retransmission before giving up on a delivery attempt.</p><hr><h3 id="snapshot-and-log-retention-parameters" tabindex="-1">Snapshot and Log Retention Parameters <a class="header-anchor" href="#snapshot-and-log-retention-parameters" aria-label="Permalink to &quot;Snapshot and Log Retention Parameters&quot;">​</a></h3><p>These parameters control how frequently Raft snapshots the FSM state and how many log entries are kept around after a snapshot. They affect both disk usage and how quickly a lagging node can catch up.</p><h4 id="raft-snapshot-threshold" tabindex="-1"><code>raft.snapshot_threshold</code> <a class="header-anchor" href="#raft-snapshot-threshold" aria-label="Permalink to &quot;`raft.snapshot_threshold`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  snapshot_threshold</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 5000</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.snapshot_threshold</code><br><strong>Default:</strong> <code>500</code></p><p>The number of committed log entries that must accumulate before Raft automatically takes a snapshot of the FSM state. After a snapshot, log entries older than the snapshot are compacted away.</p><p><strong>Effect on operations:</strong></p><ul><li><strong>Lower values</strong> (e.g., <code>500</code>): snapshots are taken frequently, keeping the log small. A restarting node receives a recent snapshot and has fewer log entries to replay, but snapshot writes happen more often, adding brief I/O bursts.</li><li><strong>Higher values</strong> (e.g., <code>5000</code>): less frequent snapshots mean less I/O overhead during normal operation, but a lagging node may have more log entries to replay when catching up.</li></ul><p>At 10 block/second, <code>snapshot_threshold: 5000</code> takes a snapshot roughly every 8.3 minutes (500 seconds).</p><hr><h4 id="raft-trailing-logs" tabindex="-1"><code>raft.trailing_logs</code> <a class="header-anchor" href="#raft-trailing-logs" aria-label="Permalink to &quot;`raft.trailing_logs`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  trailing_logs</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 18000</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.trailing_logs</code><br><strong>Default:</strong> <code>200</code></p><p>The number of log entries to <strong>retain after a snapshot</strong> is taken. These entries act as a catch-up buffer: a node that missed fewer than <code>trailing_logs</code> entries since the last snapshot can replay from the log without needing to transfer the full snapshot.</p><p><strong>Effect on operations:</strong></p><ul><li><strong>Lower values</strong> (e.g., <code>200</code>): tighter disk usage; a node that misses even a few minutes of operation must receive a full snapshot on rejoin.</li><li><strong>Higher values</strong> (e.g., <code>18000</code>): a lagging node can catch up via log replay without needing a full snapshot transfer, reducing the cost of brief outages. At 1 block/second (<code>block_time: &quot;1s&quot;</code>), <code>trailing_logs: 18000</code> covers ~5 hours; at 10 block/second, ~30 minutes.</li></ul><p>Set this high enough to cover your typical maintenance window (restart, upgrade, brief network partition). Scale proportionally with your chain&#39;s block rate.</p><hr><h4 id="raft-snap-count" tabindex="-1"><code>raft.snap_count</code> <a class="header-anchor" href="#raft-snap-count" aria-label="Permalink to &quot;`raft.snap_count`&quot;">​</a></h4><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  snap_count</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 3</span></span></code></pre></div><p><strong>CLI:</strong> <code>--evnode.raft.snap_count</code><br><strong>Default:</strong> <code>3</code></p><p>The number of snapshot files to retain on disk. Older snapshots are deleted when new ones are created. Keeping 2–3 snapshots provides a rollback option in case the latest snapshot is corrupt.</p><hr><h3 id="recommended-production-configuration" tabindex="-1">Recommended Production Configuration <a class="header-anchor" href="#recommended-production-configuration" aria-label="Permalink to &quot;Recommended Production Configuration&quot;">​</a></h3><p>The following configuration is recommended for a <strong>5-node cluster on a network with RTT_MAX ≤ 25ms</strong> (typical for nodes in the same region). It was validated by an extensive sweep of 10 configurations across 150 SIGTERM kill cycles and 50 latency-injection cycles, with zero undetected failures and zero split-brain events recorded.</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;"># evnode.yaml — paste this raft section into every node&#39;s config</span></span>\n<span class="line"><span style="color:#A0A0A0;"># Replace node_id, raft_addr, and peers with your actual values.</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">node</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  aggregator</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#94EEFF;">raft</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  enable</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> true</span></span>\n<span class="line"><span style="color:#94EEFF;">  node_id</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">node-1</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#A0A0A0;">                    # unique per node</span></span>\n<span class="line"><span style="color:#94EEFF;">  raft_addr</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">0.0.0.0:5001</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  raft_dir</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/var/lib/ev-node/raft</span><span style="color:#BFF3C280;">&quot;</span><span style="color:#A0A0A0;">    # must be persistent</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">  # Remote peers list — different on every node</span></span>\n<span class="line"><span style="color:#94EEFF;">  peers</span><span style="color:#767676;">:</span><span style="color:#B8A6FF;"> &gt;-</span></span>\n<span class="line"><span style="color:#BFF3C2;">    node-2@10.0.0.2:5001,</span></span>\n<span class="line"><span style="color:#BFF3C2;">    node-3@10.0.0.3:5001,</span></span>\n<span class="line"><span style="color:#BFF3C2;">    node-4@10.0.0.4:5001,</span></span>\n<span class="line"><span style="color:#BFF3C2;">    node-5@10.0.0.5:5001</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">  # Timing — tuned for RTT_MAX ≤ 25ms</span></span>\n<span class="line"><span style="color:#94EEFF;">  heartbeat_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">    &quot;</span><span style="color:#BFF3C2;">92ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  election_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">     &quot;</span><span style="color:#BFF3C2;">368ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  leader_lease_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">46ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  send_timeout</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;">         &quot;</span><span style="color:#BFF3C2;">50ms</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">  # Log retention</span></span>\n<span class="line"><span style="color:#94EEFF;">  trailing_logs</span><span style="color:#767676;">:</span><span style="color:#FFECB6;">      18000</span></span>\n<span class="line"><span style="color:#94EEFF;">  snapshot_threshold</span><span style="color:#767676;">:</span><span style="color:#FFECB6;"> 5000</span></span>\n<span class="line"><span style="color:#94EEFF;">  snap_count</span><span style="color:#767676;">:</span><span style="color:#FFECB6;">         3</span></span></code></pre></div><p><strong>Adapting for different RTT values:</strong></p><p>Measure RTT_MAX first and scale the timing parameters:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span>heartbeat_timeout    = RTT_MAX × 4</span></span>\n<span class="line"><span>election_timeout     = heartbeat_timeout × 4</span></span>\n<span class="line"><span>leader_lease_timeout = heartbeat_timeout / 2</span></span>\n<span class="line"><span>send_timeout         = RTT_MAX × 3</span></span></code></pre></div><hr><h2 id="interaction-with-p2p" tabindex="-1">Interaction with P2P <a class="header-anchor" href="#interaction-with-p2p" aria-label="Permalink to &quot;Interaction with P2P&quot;">​</a></h2><p>Even in a Raft cluster, each node must have P2P configured. Raft handles <strong>hot replication</strong> — it replicates the latest block state to all followers in near real-time. But if a node falls far enough behind that the missing entries have already been compacted out of the Raft log (i.e., it missed more entries than <code>trailing_logs</code>), it receives a Raft snapshot to jump to the current head. Historical blocks between the node&#39;s last known state and the snapshot are then fetched via the <strong>P2P network or DA layer</strong>.</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">p2p</span><span style="color:#767676;">:</span></span>\n<span class="line"><span style="color:#94EEFF;">  listen_address</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/ip4/0.0.0.0/tcp/26656</span><span style="color:#BFF3C280;">&quot;</span></span>\n<span class="line"><span style="color:#94EEFF;">  peers</span><span style="color:#767676;">:</span><span style="color:#BFF3C280;"> &quot;</span><span style="color:#BFF3C2;">/ip4/&lt;PEER_IP&gt;/tcp/26656/p2p/&lt;PEER_ID&gt;,...</span><span style="color:#BFF3C280;">&quot;</span></span></code></pre></div><p>Ensure P2P ports are open between nodes in addition to the Raft port.</p><hr><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><p>Track these metrics (available via Prometheus if <code>metrics.enabled: true</code>) to catch problems early:</p><table tabindex="0"><thead><tr><th>Signal</th><th>What it means</th></tr></thead><tbody><tr><td>Frequent leadership changes</td><td>Network instability, asymmetric packet loss, or overloaded nodes</td></tr><tr><td>Growing applied-index lag</td><td>FSM cannot keep up with commits; check CPU and disk I/O</td></tr><tr><td>Snapshot transfers</td><td>Node fell behind <code>trailing_logs</code> entries — check network and disk</td></tr><tr><td>Election timeouts</td><td>Heartbeats are being dropped; check MTU, firewall rules, network congestion</td></tr></tbody></table><p>See the <a href="./../operations/monitoring">Monitoring guide</a> for the full Prometheus metric list.</p>',141)])])}]]);export{o as __pageData,n as default};
